import React, { useState } from 'react';

const NuevaEmpresa = () => {
  const [formulario, setFormulario] = useState({
    nombreComercial: '',
    denominacionSocial: '',
    nit: '',
    fechaFundacion: '',
    fechaCierre: '',
    tamano: '',
    imagen: '',
    premios: '',
  });

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormulario({ ...formulario, [name]: value });
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log('Empresa registrada:', formulario);
    // Aquí podrías hacer fetch/axios al backend 🔥
  };

  return (
    <div className="min-h-screen bg-[#f2f0df] flex justify-center items-start p-6">
      <form 
        onSubmit={handleSubmit}
        className="bg-white shadow-xl rounded-xl p-6 w-full max-w-2xl space-y-4"
      >
        <h2 className="text-2xl font-bold text-[#9fa56c] text-center mb-4">Registrar Nueva Empresa</h2>

        {/* Nombre Comercial */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">Nombre Comercial</label>
          <input
            type="text"
            name="nombreComercial"
            value={formulario.nombreComercial}
            onChange={handleChange}
            className="w-full p-2 rounded border border-gray-300"
            required
          />
        </div>

        {/* Denominación Social */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">Denominación Social</label>
          <input
            type="text"
            name="denominacionSocial"
            value={formulario.denominacionSocial}
            onChange={handleChange}
            className="w-full p-2 rounded border border-gray-300"
            required
          />
        </div>

        {/* NIT */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">NIT</label>
          <input
            type="text"
            name="nit"
            value={formulario.nit}
            onChange={handleChange}
            className="w-full p-2 rounded border border-gray-300"
            required
          />
        </div>

        {/* Fechas */}
        <div className="flex flex-col sm:flex-row gap-4">
          <div className="flex-1">
            <label className="block text-gray-700 font-medium mb-1">Fecha de Fundación</label>
            <input
              type="date"
              name="fechaFundacion"
              value={formulario.fechaFundacion}
              onChange={handleChange}
              className="w-full p-2 rounded border border-gray-300"
            />
          </div>
          <div className="flex-1">
            <label className="block text-gray-700 font-medium mb-1">Fecha de Cierre</label>
            <input
              type="date"
              name="fechaCierre"
              value={formulario.fechaCierre}
              onChange={handleChange}
              className="w-full p-2 rounded border border-gray-300"
            />
          </div>
        </div>

        {/* Tamaño Empresa */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">Tamaño de Empresa</label>
          <input
            type="text"
            name="tamano"
            value={formulario.tamano}
            onChange={handleChange}
            className="w-full p-2 rounded border border-gray-300"
          />
        </div>

        {/* Imagen */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">URL de Imagen</label>
          <input
            type="url"
            name="imagen"
            value={formulario.imagen}
            onChange={handleChange}
            className="w-full p-2 rounded border border-gray-300"
          />
        </div>

        {/* Premios */}
        <div>
          <label className="block text-gray-700 font-medium mb-1">Premios Otorgados</label>
          <input
            type="text"
            name="premios"
            value={formulario.premios}
            onChange={handleChange}
            className="w-full p-2 rounded border border-gray-300"
            placeholder="Ej: Premio Nacional, Premio Exportador"
          />
        </div>

        {/* Botón */}
        <div className="text-center mt-6">
          <button
            type="submit"
            className="bg-[#9fa56c] hover:bg-[#8a944e] text-white px-6 py-2 rounded-full font-semibold"
          >
            Guardar Empresa
          </button>
        </div>
      </form>
    </div>
  );
};

export default NuevaEmpresa;
